cluded_handlers";a:0:{}}s:7:"variant";a:1:{s:17:"excluded_variants";a:0:{}}s:5:"batch";a:5:{s:25:"default_batch_export_size";i:500;s:25:"default_batch_import_size";i:100;s:25:"default_batch_update_size";i:500;s:25:"default_batch_delete_size";i:500;s:24:"default_batch_email_size";i:500;}s:5:"purge";a:1:{s:9:"cron_size";i:100;}s:4:"test";a:2:{s:5:"types";s:3347:"checkbox:\012  - true\012color:\012  - ''#ffffcc''\012  - ''#ffffcc''\012  - ''#ccffff''\012email:\012  - ''example@example.com''\012  - ''test@test.com''\012  - ''random@random.com''\012language_select:\012  - en\012machine_name:\012  - ''loremipsum''\012  - ''oratione''\012  - ''dixisset''\012tel:\012  - ''123-456-7890''\012  - ''098-765-4321''\012textarea:\012  - ''Lorem ipsum dolor sit amet, consectetur adipiscing elit. Negat esse eam, inquit, propter se expetendam. Primum Theophrasti, Strato, physicum se voluit; Id mihi magnum videtur. Itaque mihi non satis videmini considerare quod iter sit naturae quaeque progressio. Quare hoc videndum est, possitne nobis hoc ratio philosophorum dare. Est enim tanti philosophi tamque nobilis audacter sua decreta defendere.''\012  - ''Huius, Lyco, oratione locuples, rebus ipsis ielunior. Duo Reges: constructio interrete. Sed haec in pueris; Sed utrum hortandus es nobis, Luci, inquit, an etiam tua sponte propensus es? Sapiens autem semper beatus est et est aliquando in dolore; Immo videri fortasse. Paulum, cum regem Persem captum adduceret, eodem flumine invectio? Et ille ridens: Video, inquit, quid agas;''\012  - ''Quae cum dixisset, finem ille. Quamquam non negatis nos intellegere quid sit voluptas, sed quid ille dicat. Progredientibus autem aetatibus sensim tardeve potius quasi nosmet ipsos cognoscimus. Gloriosa ostentatio in constituendo summo bono. Qui-vere falsone, quaerere mittimus-dicitur oculis se privasse; Duarum enim vitarum nobis erunt instituta capienda. Comprehensum, quod cognitum non habet? Qui enim existimabit posse se miserum esse beatus non erit. Causa autem fuit huc veniendi ut quosdam hinc libros promerem. Nunc omni virtuti vitium contrario nomine opponitur.''\012text_format:\012  - value: ''<p>Lorem ipsum dolor sit amet, consectetur adipiscing elit. Negat esse eam, inquit, propter se expetendam. Primum Theophrasti, Strato, physicum se voluit; Id mihi magnum videtur. Itaque mihi non satis videmini considerare quod iter sit naturae quaeque progressio. Quare hoc videndum est, possitne nobis hoc ratio philosophorum dare. Est enim tanti philosophi tamque nobilis audacter sua decreta defendere.</p>''\012  - value: ''<p>Huius, Lyco, oratione locuples, rebus ipsis ielunior. Duo Reges: constructio interrete. Sed haec in pueris; Sed utrum hortandus es nobis, Luci, inquit, an etiam tua sponte propensus es? Sapiens autem semper beatus est et est aliquando in dolore; Immo videri fortasse. Paulum, cum regem Persem captum adduceret, eodem flumine invectio? Et ille ridens: Video, inquit, quid agas;</p>''\012  - value: ''<p>Quae cum dixisset, finem ille. Quamquam non negatis nos intellegere quid sit voluptas, sed quid ille dicat. Progredientibus autem aetatibus sensim tardeve potius quasi nosmet ipsos cognoscimus. Gloriosa ostentatio in constituendo summo bono. Qui-vere falsone, quaerere mittimus-dicitur oculis se privasse; Duarum enim vitarum nobis erunt instituta capienda. Comprehensum, quod cognitum non habet? Qui enim existimabit posse se miserum esse beatus non erit. Causa autem fuit huc veniendi ut quosdam hinc libros promerem. Nunc omni virtuti vitium contrario nomine opponitur.</p>''\012url:\012  - ''http://example.com''\012  - ''http://test.com''\012webform_email_confirm:\012  - ''example@example.com''\012  - ''test@test.com''\012  - ''random@random.com''\012webform_email_multiple:\012  - ''example@example.com, test@test.com, random@random.com''\012webform_time:\012  - ''09:00''\012  - ''17:00''\012";s:5:"names";s:547:"first_name:\012  - ''John''\012  - ''Paul''\012  - ''Ringo''\012  - ''George''\012last_name:\012  - ''Lennon''\012  - ''McCartney''\012  - ''Starr''\012  - ''Harrison''\012address:\012  - ''10 Main Street''\012  - ''11 Brook Alley Road. APT 1''\012zip:\012  - ''11111''\012  - ''12345''\012  - ''12345-6789''\012postal_code:\012  - ''11111''\012  - ''12345''\012  - ''12345-6789''\012phone:\012  - ''123-456-7890''\012  - ''098-765-4321''\012fax:\012  - ''123-456-7890''\012  - ''098-765-4321''\012city:\012  - ''Springfield''\012  - ''Pleasantville''\012  - ''Hill Valley''\012url:\012  - ''http://example.com''\012  - ''http://test.com''\012default:\012  - ''Loremipsum''\012  - ''Oratione''\012  - ''Dixisset''\012";}s:2:"ui";a:9:{s:13:"video_display";s:6:"dialog";s:13:"help_disabled";b:0;s:15:"dialog_disabled";b:0;s:18:"offcanvas_disabled";b:0;s:19:"promotions_disabled";b:0;s:16:"support_disabled";b:0;s:12:"details_save";b:1;s:16:"description_help";b:1;s:12:"toolbar_item";b:0;}s:9:"libraries";a:1:{s:18:"excluded_libraries";a:2:{i:0;s:7:"choices";i:1;s:13:"jquery.chosen";}}s:12:"requirements";a:3:{s:3:"cdn";b:1;s:21:"clientside_validation";b:1;s:4:"spam";b:1;}s:20:"third_party_settings";a:1:{s:7:"captcha";a:1:{s:27:"replace_administration_mode";b:1;}}}');
