INSERT INTO public.drupal_config (collection, name, data) VALUES ('', 'user.mail', 'a:11:{s:5:"_core";a:1:{s:19:"default_config_hash";s:43:"6CZIzFifRq3qbdq3n3nDpEOO4hWIQtKOAQNPvGNGKeM";}s:8:"langcode";s:5:"pt-br";s:14:"cancel_confirm";a:2:{s:7:"subject";s:78:"Solicita\303\247\303\243o de cancelamento de conta para [user:display-name] em [site:name]";s:4:"body";s:382:"[user:display-name]\015\012\015\012Um pedido de cancelamento de sua conta foi feito em [site:name].\015\012\015\012Agora voc\303\252 pode cancelar sua conta em [site:url-brief] clicando neste link ou copiando e colando no seu navegador:\015\012\015\012[user:cancel-url]\015\012\015\012NOTA: O cancelamento da sua conta n\303\243o \303\251 revers\303\255vel.\015\012\015\012Este link expira em um dia e nada acontecer\303\241 se ele n\303\243o for usado.\015\012\015\012-- Equipe [site:name]";}s:14:"password_reset";a:2:{s:7:"subject";s:77:"Novas informa\303\247\303\265es de autentica\303\247\303\243o para [user:display-name] em [site:name]";s:4:"body";s:442:"[user:display-name],\015\012\015\012Uma solicita\303\247\303\243o para resetar sua senha foi feita em [site:name].\015\012\015\012Voc\303\252 pode se autenticar agora clicando neste link ou copiando e colando em seu navegador:\015\012\015\012[user:one-time-login-url]\015\012\015\012Esse link pode ser usado para se autenticar apenas uma vez e o levar\303\241 a uma p\303\241gina onde voc\303\252 pode definir sua senha. Ele ir\303\241 expirar dentro de um dia e, caso n\303\243o seja usado, nada ser\303\241 alterado.\015\012\015\012--  Equipe [site:name]";}s:22:"register_admin_created";a:2:{s:7:"subject";s:63:"Um administrador criou uma conta para voc\303\252 no site [site:name]";s:4:"body";s:491:"[user:display-name],\015\012\015\012Um administrador do site [site:name] criou uma conta para voc\303\252. Voc\303\252 pode se autenticar clicando neste link ou copiando e colando em seu navegador:\015\012\015\012[user:one-time-login-url]\015\012\015\012Esse link pode ser usado para se autenticar apenas uma vez e o levar\303\241 a uma p\303\241gina onde voc\303\252 pode definir sua senha.\015\012\015\012Ap\303\263s configurar sua senha, voc\303\252 poder\303\241 se autenticar em [site:login-url] no futuro usando:\015\012\015\012usu\303\241rio: [user:name]\015\012senha: Sua senha\015\012\015\012--  Equipe [site:name]";}s:29:"register_no_approval_required";a:2:{s:7:"subject";s:57:"Detalhes de conta para [user:display-name] em [site:name]";s:4:"body";s:470:"[user:display-name],\015\012\015\012\015\012Obrigado por se registrar em [site:name]. Voc\303\252 pode se autenticar clicando neste link ou copiando e colando em seu navegador:\015\012\015\012[user:one-time-login-url]\015\012\015\012Esse link pode ser usado para se autenticar apenas uma vez e o levar\303\241 a uma p\303\241gina onde voc\303\252 pode definir sua senha.\015\012\015\012Ap\303\263s configurar sua senha, voc\303\252 poder\303\241 se autenticar em [site:login-url] no futuro usando:\015\012\015\012usu\303\241rio: [user:name]\015\012senha: Sua senha\015\012\015\012--  Equipe [site:name]";}s:25:"register_pending_approval";a:2:{s:7:"subject";s:102:"Detalhes de conta para [user:display-name] em [site:name] (aguardando aprova\303\247\303\243o de um administrador)";s:4:"body";s:272:"[user:display-name],\015\012\015\012Obrigado por se registrar em [site:name]. Sua nova conta est\303\241 pendente de aprova\303\247\303\243o. Assim que aprovado voc\303\252 receber\303\241 um e-mail contendo as informa\303\247\303\265es de como efetuar o log in, bem como sua senha e outros detalhes.\015\012\015\012--  Equipe [site:name]";}s:31:"register_pending_approval_admin";a:2:{s:7:"subject";s:102:"Detalhes de conta para [user:display-name] em [site:name] (aguardando aprova\303\247\303\243o de um administrador)";s:4:"body";s:74:"[user:display-name] solicitou a cria\303\247\303\243o de uma conta.\015\012\015\012[user:edit-url]";}s:16:"status_activated";a:2:{s:7:"subject";s:68:"Detalhes da conta para [user:display-name] em [site:name] (aprovada)";s:4:"body";s:475:"[user:display-name],\015\012\015\012Sua conta em [site:name] foi ativada.\015\012\015\012Voc\303\252 pode se autenticar clicando neste link ou copiando e colando em seu navegador:\015\012\015\012[user:one-time-login-url]\015\012\015\012Esse link pode ser usado para se autenticar apenas uma vez e o levar\303\241 a uma p\303\241gina onde voc\303\252 pode definir sua senha.\015\012\015\012Ap\303\263s configurar sua senha, voc\303\252 poder\303\241 se autenticar em [site:login-url] no futuro usando:\015\012\015\012usu\303\241rio: [user:account-name]\015\012senha: Sua senha\015\012\015\012--  Equipe [site:name]";}s:14:"status_blocked";a:2:{s:7:"subject";s:69:"Detalhes da conta para [user:display-name] em [site:name] (bloqueada)";s:4:"body";s:89:"[user:display-name],\015\012\015\012Sua conta em [site:name] foi bloqueada.\015\012\015\012--  Equipe [site:name]";}s:15:"status_canceled";a:2:{s:7:"subject";s:69:"Detalhes da conta para [user:display-name] em [site:name] (cancelada)";s:4:"body";s:89:"[user:display-name],\015\012\015\012Sua conta em [site:name] foi cancelada.\015\012\015\012--  Equipe [site:name]";}}');
